```
// AI_Sponge script

// Define the entity's behavior
function Update()
{
    // If the sponge has been seen by the player,
    if (entity.IsSeenByPlayer())
    {
        // Teleport the sponge to a random location within a certain range
        entity.TeleportRandom(10);
    }
    // Otherwise, if the sponge is not seen by the player,
    else
    {
        // Make the sponge vanish from the player's sight by reducing its opacity
        entity.SetOpacity(0);
    }
}
